const item = $input.item.json;

// Normalise status to a canonical event key
const rawStatus = (item.orderStatus || '').toLowerCase();

const STATUS_MAP = {
  'confirmed':      'ORDER_CONFIRMED',
  'order_confirmed':'ORDER_CONFIRMED',
  'placed':         'ORDER_CONFIRMED',
  'new':            'ORDER_CONFIRMED',
  'shipped':        'ORDER_SHIPPED',
  'dispatched':     'ORDER_SHIPPED',
  'in_transit':     'ORDER_SHIPPED',
  'out_for_delivery': 'OUT_FOR_DELIVERY',
  'out for delivery': 'OUT_FOR_DELIVERY',
  'on_the_way':     'OUT_FOR_DELIVERY',
  'delivered':      'ORDER_DELIVERED',
  'completed':      'ORDER_DELIVERED',
};

const eventType = STATUS_MAP[rawStatus] || null;

// Validate required fields
const missingPhone = !item.customerPhone || item.customerPhone.trim() === '';
const missingOrderId = !item.orderId || item.orderId === 'UNKNOWN';

return {
  json: {
    ...item,
    eventType,
    isValidEvent: eventType !== null,
    hasPhone: !missingPhone,
    validationError: missingPhone ? 'Missing customer phone' : missingOrderId ? 'Missing order ID' : null
  }
};

const item = $input.item.json;

// ─── Message Templates ──────────────────────────────────────────────────────
const templates = {
  ORDER_CONFIRMED: [
    `Hi ${item.customerName}! 🎉`,
    `Your order *#${item.orderId}* has been confirmed.`,
    `💰 Total: ${item.currency} ${item.orderTotal}`,
    `We'll notify you as soon as it ships. Thank you for shopping with us!`
  ].join('\n'),

  ORDER_SHIPPED: [
    `Hi ${item.customerName}! 📦`,
    `Great news — your order *#${item.orderId}* has shipped!`,
    item.trackingNumber ? `🔍 Tracking: ${item.trackingNumber}` : null,
    item.trackingUrl    ? `🔗 Track here: ${item.trackingUrl}` : null,
    item.estimatedDelivery ? `📅 Expected delivery: ${item.estimatedDelivery}` : null,
    `We'll keep you posted every step of the way.`
  ].filter(Boolean).join('\n'),

  OUT_FOR_DELIVERY: [
    `Hi ${item.customerName}! 🚚`,
    `Your order *#${item.orderId}* is out for delivery today!`,
    `Please make sure someone is available to receive it.`,
    `If you have any questions, reply to this message.`
  ].join('\n'),

  ORDER_DELIVERED: [
    `Hi ${item.customerName}! ✅`,
    `Your order *#${item.orderId}* has been delivered.`,
    `We hope you love your purchase! 🛍️`,
    `If anything is missing or damaged, please contact us within 48 hours.`,
    `Thank you for choosing us!`
  ].join('\n')
};

const messageText = templates[item.eventType] || `Hi ${item.customerName}, your order #${item.orderId} status has been updated to: ${item.orderStatus}.`;

// Sanitise phone number — ensure it starts with country code, digits only
const sanitisedPhone = item.customerPhone
  .replace(/\D/g, '')
  .replace(/^0+/, '');

return {
  json: {
    ...item,
    messageText,
    recipientPhone: sanitisedPhone,
    sentAt: new Date().toISOString()
  }
};

const item = $input.item.json;

// Capture WhatsApp API response
const apiResponse = item;
const waMessageId = apiResponse?.messages?.[0]?.id || 'N/A';
const deliveryStatus = apiResponse?.messages ? 'SENT' : 'FAILED';

return {
  json: {
    ...($input.item.json),
    waMessageId,
    deliveryStatus,
    loggedAt: new Date().toISOString()
  }
};

// Error handler — captures failures from Send or Sheet nodes
const errorDetails = {
  failedAt: new Date().toISOString(),
  orderId: $input.item.json?.orderId || 'N/A',
  eventType: $input.item.json?.eventType || 'N/A',
  recipientPhone: $input.item.json?.recipientPhone || 'N/A',
  errorMessage: $input.item.json?.error?.message || 'Unknown error',
  errorCode: $input.item.json?.error?.code || 'N/A'
};

console.error('[OrderTracking] ERROR:', JSON.stringify(errorDetails));

return { json: errorDetails };
